css_snippet:
:root {
  --bg: #ffffff;
  --surface: #f8f9fa;
  --text: #1a1a2e;
  --text-muted: #6b7280;
  --accent: #2563eb;
  --accent-light: #dbeafe;
  --border: #e5e7eb;

  --font-h: 'Plus Jakarta Sans', 'Inter', system-ui, sans-serif;
  --font-b: 'Inter', system-ui, sans-serif;

  --radius: 8px;
  --shadow-md: 0 4px 12px rgba(0,0,0,0.08);
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-b);
  font-size: 16px;
  line-height: 1.65;
}

h1, h2, h3 {
  font-family: var(--font-h);
  font-weight: 600;
  line-height: 1.25;
  color: var(--text);
}
